I'm just now implementing the pagination so i'm looking for a best way to do it. With pagination may be there are not gonna be more than 100 rows on a page. 
```
function convertJsonToTable(jsonData, keys, containerId, tableClassName) {
    //Patterns for table thead & tbody
    var tbl = "<table border='0' cellpadding='1' cellspacing='1' id='" + containerId + "' class='" + tableClassName + "'>{0}{1}</table>";
    var th = "<thead class=\"ui-widget-header\">{0}</thead>";
    var tb = "<tbody>{0}</tbody>";
    var tr = "<tr>{0}</tr>";
    var thRow = "<th{1}>{0}</th>";
    var tdRow = "<td>{0}</td>";
    var thCon = "";
    var tbCon = "";
    var trCon = "";

    if (keys && jsonData) {
        //Creating all table headers
        
        for(rey in keys){
                thCon += thRow.format(keys[rey],' id="th_'+rey+'"');
        }
        th = th.format(tr.format(thCon));

        
        //Creating all table rows from Json data
        if (typeof(jsonData[0]) == "object") {
            for (i = 0; i < jsonData.length; i++) {
                for(rey in keys){
                    tbCon += tdRow.format(jsonData[i][rey]);
                }
                trCon += tr.format(tbCon);
                tbCon = "";
            }
        }
        tb = tb.format(trCon);

        tbl = tbl.format(th, tb);
        return tbl;
    }

    return null;
}
```

